#include<bits/stdc++.h>
using namespace std;
long long f[200010][2],max1[200010][2],id[200020][2];
long long k[200010][2],g[200010][2],p[200010];
long long ans;
vector<pair<int,int>> mp[200010];
void dfs(int x,int fa=-1)
{
    max1[x][0]=max1[x][1]=-1e9;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            dfs(v,x);
            p[v]=val;
            f[x][0]+=max(f[v][0],f[v][1]+val);
            long long tmp=f[v][0]+val-max(f[v][0],f[v][1]+val);
            if(tmp>max1[x][0])
            {
                max1[x][1]=max1[x][0];
                id[x][1]=id[x][0];
                max1[x][0]=tmp;
                id[x][0]=v;
            }
            else if(tmp>max1[x][1])
            {
                max1[x][1]=tmp;
                id[x][1]=v;
            }
        }
    }
    f[x][1]=f[x][0]+max1[x][0];
}
void dp(int x,int fa=-1)
{
    ans=max(ans,g[x][0]);
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            if(id[x][0]==v)
            {
                swap(max1[x][0],max1[x][1]);
                swap(id[x][0],id[x][1]);
            }
            k[x][0]=g[x][0]-max(f[v][0],f[v][1]+val);
            k[x][1]=k[x][0]+max1[x][0];
            if(fa!=-1)
            {
                k[x][1]=max(k[x][1],k[x][0]+k[fa][0]+p[x]-max(k[fa][0],k[fa][1]+p[x]));
            }
            g[v][0]=f[v][0]+max(k[x][0],k[x][1]+val);
            if(max1[x][0]<max1[x][1])
            {
                swap(max1[x][0],max1[x][1]);
                swap(id[x][0],id[x][1]);
            }
            dp(v,x);
        }
    }
}
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dfs(1);
    g[1][0]=f[1][0];
    dp(1);
    printf("%lld",ans);
    return 0;
}
